const body = $input.item.json;
const content = body.choices[0].message.content;
const parsed = JSON.parse(content);
return { reply: parsed.message || parsed.reply || "Sorry, something went wrong. Please try again!", status: parsed.status || "in_progress", data: parsed.data || null };

