const body = $('Public Chat Webhook').item.json.body || {};
const parsed = $('Parse AI Response').item.json || {};
const data = parsed.data || {};
const history = body.history || [];
const transcript = history.map(m => (m.role||m.sender||'') + ': ' + (m.content||m.text||'')).join('\n');
return [{ json: {
  conversation_id: body.session_id || body.conversation_id || '',
  status: 'trial_requested',
  name: data.name || '',
  email: data.email || '',
  phone: data.phone || '',
  enquiry_topic: data.classInterest || 'Free Trial Booking',
  enquiry_summary: data.enquiry_summary || 'Visitor booked a free trial via the chat widget.',
  transcript: transcript,
  page_url: body.page_url || body.url || '',
  chatbot: 'BFC Website Chatbot',
  is_lead: 'Yes',
  urgency: 'Normal'
} }];

